import 'package:flutter/material.dart';import '../state/passenger_controller.dart';class RideHistoryScreen extends StatelessWidget{const RideHistoryScreen({super.key,required this.controller});final PassengerController controller;@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:Text(controller.t('rideHistory'))),body:FutureBuilder(future:controller.api.getJson('/v1/passengers/${controller.session!.userId}/bookings'),builder:(c,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());final items=((s.data?['bookings']??[]) as List);if(items.isEmpty)return Center(child:Text(controller.t('rides')));return ListView.builder(itemCount:items.length,itemBuilder:(c,i)=>ListTile(leading:const Icon(Icons.electric_rickshaw),title:Text((items[i]['destination']?['address']??'Ride').toString()),subtitle:Text((items[i]['status']??'').toString()))); }));}
